import { Outlet, Link } from "react-router-dom";

const Layout = () => {
  return (
    <>
      <div>
        <Link to="html">HTML</Link>
        <Link to="css">CSS</Link>
        <Link to="Figma">Figma</Link>
      </div>
      <Outlet />
    </>
  );
};
export default Layout;
